DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "parserMultiAnswer.pl",
  "contextCurrency.pl",
  "contextPercent.pl",
  "parserLinearRelation.pl",
  "randomPerson.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$p = randomPerson();
Context("Percent");
$r1 = random(0.01, 0.03, 0.005);
$rate1 = Percent($r1);
$r2 = random(0.035, 0.07, 0.005);
$rate2 = Percent($r2);
Context("Currency")->flags->set(trimTrailingZeros => 1);
$x = random(1000, 2000, 100);
$y = random(2100, 4000, 100);
$X = Currency($x);
$Y = Currency($y);
$t = $x + $y;
$total = Currency($t);
$i = $r1 * $x + $r2 * $y;
$final = $total - Currency($i);
Context("LinearRelation")->variables->are(x => 'Real', y => 'Real');
@eq = (LinearRelation("x + y = $t"), LinearRelation("$r1 x - $r2 y = -$i"));
$m = MultiAnswer(@eq)->with(
  singleResult => 0,
  checker => sub {
      my ( $c, $s, $self ) = @_;
      return [1,1] if ($c->[0] == $s->[0] && $c->[1] == $s->[1] || $c->[1] == $s->[0] && $c->[0] == $s->[1]);
      return [1,0] if ($c->[0] == $s->[0] || $c->[1] == $s->[0]);
      return [0,1] if ($c->[0] == $s->[1] || $c->[1] == $s->[1]);
      return [0,0];
  }
);

############################################################
# Body
############################################################

BEGIN_PGML
[$p] invested a total of [`[$total]`] in two investments. [$p->Their] savings account pays [`[$rate1]`] interest annually. A riskier stock investment lost [`[$rate2]`] at the end of the year. At the end of the year, [$p]'s total fell from [`[$total]`] to [`[$final]\text{.}`] How much money did [$p->they] invest in each account?

[@KeyboardInstructions('Using [`x`] (savings investment) and [`y`] (stock investment) as the variables, give two equations that form a system of equations that is appropriate for this exercise.')@]**

[_]{$m}{16}

[_]{$m}{16}

[@KeyboardInstructions('Solve the system and enter the amount invested in savings here.')@]**

[_]{$X}{16}

[@KeyboardInstructions('Enter the amount invested in stock here.')@]**

[_]{$Y}{16}

END_PGML

